{
  "title": "अमेज़न ऑरिओला के साथ पठन क्षमता का पैमाना",
  "group": "ऑरिओला के पैमाने",
  "options": [
    {
      "text": "एक एकल पठन प्रतिलिपि तक सीमित है",
      "hint": "ऑरिओला की पैमाने की विशेषताओं पर विचार करें।"
    },
    {
      "text": "कोई पठन पैमाना संभव नहीं है",
      "hint": "क्या यह ऑरिओला की क्षमताओं के साथ संगत है?"
    },
    {
      "text": "15 पठन प्रतिलिपियों का समर्थन करता है"
    },
    {
      "text": "असीमित पठन प्रतिलिपियाँ",
      "hint": "एक व्यावहारिक सीमा का विचार करें।"
    }
  ],
  "questionProse": [
    "अमेज़न ऑरिओला कितनी अधिकतम पठन प्रतिलिपियाँ समर्थन करता है?"
  ],
  "explanationProse": [
    "अमेज़न ऑरिओला **15 पठन प्रतिलिपियों** तक का समर्थन करता है, जो आपके पठन ऑपरेशन को बड़े पैमाने पर पैमाना करने की अनुमति देता है। ये प्रतिलिपियाँ निम्नलिखित लाभ प्रदान करती हैं:\n\n      - **प्रतिलिपियों के बीच लगभग तत्काल प्रतिलिपि बनाना**\n      - **मुख्य इंस्टेंस पर न्यूनतम प्रदर्शन प्रभाव**\n      - **पठन कार्यभार का कुशल वितरण**\n\n      यह संरचना भारी पठन आवश्यकताओं वाले एप्लिकेशनों के लिए क्षैतिज पैमाने की अनुमति देती है।\n\n      [ऑरिओला पठन प्रतिलिपियों के बारे में अधिक जानें](https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Replicas.html)"
  ]
}
